(function(w){class P{constructor(){this.init()}init(){w.pytml=this;this.processPage()}run(c,i){try{let o='';let vars='';for(let k in i){let v=i[k];if(typeof v==='number'){vars+=`var ${k}=${v};`}else{vars+=`var ${k}="${v}";`}}let js=vars;let lines=c.split('\n');for(let line of lines){line=line.trim();if(line.startsWith('print(')){let x=line.slice(6,-1);js+=`o+=String(${x})+'\\n';`}else if(line.startsWith('if ')){js+=line.slice(0,-1)+'{';}else if(line==='else:'){js+='}else{';}else if(line.includes('=')){js+=line+';';}}let fn=new Function('o',js+'return o;');o=fn(o);return o||'ok';}catch(e){return'Error: '+e.message}}collect(b){let i={};let f=b.closest('[data-python-form]');if(f){f.querySelectorAll('input,select').forEach(e=>{if(e.name){i[e.name]=e.type==='number'?parseFloat(e.value):e.value}})}return i}processPage(){document.querySelectorAll('[data-python-text]').forEach(e=>{let c=e.getAttribute('data-python-text');e.textContent=this.run(`print(${c})`);});document.querySelectorAll('[data-python]').forEach(b=>{let c=b.getAttribute('data-python');let t=b.getAttribute('data-target');b.onclick=()=>{let i=this.collect(b);let r=this.run(c,i);if(t){let o=document.querySelector(t);if(o)o.textContent=r;}};});}}w.p=new P;})();
